 // 3. bind 함수 예제

 // html

 <div id="bind_paper" style="visibility: hidden;">
 <div class="bx-paper-wrap">
 <a href="#" class="focus" onclick="return false"></a>
 <div class="paper-drag"></div>
 <div class="paper-header">
 <h2 class="bx-tt"> bind 예제 #1 </h2>
 </div>
 <div class="paper-content paper-curve-btm">
 <div class="bx-desc">
 <div> bind 예제 입니다.</div>
 <div> 사용하고자 하는 template 는 </div>
 <div> 이곳 bx-desc 하위에 입력해주세요. </div>
 </div>
 </div>
 <div class="paper-btn-wrap">
 <button type="button" class="bx-btn-close">
 <i class="bw-icon i-30 i-close"></i>
 </button>
 </div>
 </div>
 </div>

 // js

 $('#bind_paper').bxPaper(
 {
 width: 500,
 height: 500,
 position: {
 x:0,
 y:0
 },
 color: 'theme',
 type: 'stitch',
 shadow: 'both',
 titleAlign: 'center',
 dimStyle: {
 color: 'black' // ref bxDim Document
 },
 enableDrag: true,
 onActivate: function(e, $elem) {
 console.log('onActivate', e, $elem);
 },
 onDrag: function (e, $elem){
 console.log('onDrag', e, $elem);
 },
 onDragStart: function (e, $elem){
 console.log('onDragStart', e, $elem);
 },
 onDragStop: function(e, $elem){
 console.log('onDragStop', e, $elem);
 },
 onClosed: function () {
 console.log('bxPaper - onClose');
 },
 onRender: function () {
 console.log('bxPaper - onRender')
 }
 }
 ).bind();

